protocols_info.assigner:
from airalogy.assigner import (
    AssignerBase,
    AssignerResult,
    assigner,
)


class Assigner(AssignerBase):
    @assigner(
        assigned_fields=[
            "cnt_powder_mass",
        ],
        dependent_fields=[
            "dispersion_volume",
            "dispersion_concentration",
        ],
        mode="auto",
    )
    def calculate_cnt_powder_mass(dependent_fields: dict) -> AssignerResult:
        dispersion_volume = dependent_fields["dispersion_volume"]
        dispersion_concentration = dependent_fields["dispersion_concentration"]
        cnt_powder_mass = dispersion_volume * dispersion_concentration
        return AssignerResult(
            assigned_fields={
                "cnt_powder_mass": cnt_powder_mass,
            },
        )

