from airalogy.assigner import (
    AssignerBase,
    AssignerResult,
    assigner,
)


class Assigner(AssignerBase):
    @assigner(
        assigned_fields=[
            "required_stock_volume",
        ],
        dependent_fields=[
            "stock_concentration",
            "target_concentration",
            "target_volume",
        ],
        mode="auto",
    )
    def calculate_required_stock_volume(dependent_fields: dict) -> AssignerResult:
        stock_concentration = dependent_fields["stock_concentration"]
        target_concentration = dependent_fields["target_concentration"]
        target_volume = dependent_fields["target_volume"]
        required_stock_volume = (
            target_volume * target_concentration / stock_concentration
        )
        return AssignerResult(
            assigned_fields={
                "required_stock_volume": required_stock_volume,
            },
        )

